INSERT INTO `productos` VALUES ('000c4267-aa73-4e9e-bf51-1554cf395566','Montale Aoud Lagoon 100 ML EDP TESTER','unisex','Montale','Un viaje a una laguna paradisíaca. Proyecta una frescura floral y solar ideal para destacar con elegancia en climas cálidos. Formato inteligente para ahorro. Tamaño: 100 ML (Tester).','Floral: Mandarina, flor de tiaré, loto, madera de oud, vetiver.',320000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('00242bd2-9fd9-4538-bc32-d46d226ce1ab','Alhambra Jean Loewe Fraiche 100 ML EDP','unisex','Maison Alhambra','Una fragancia de nicho inspirada en Louis Vuitton. Es una frescura cítrica y picante de alto nivel, limpia y muy lujosa.','Lichi, Jengibre, Bergamota, Almizcle, Notas terrosas.',67000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('00306766-f61f-4ee8-96ef-ce004071ebb0','Khadlaj Island Vanilla Dunes 100 ML DM EDP Extrait De Parfum','mujer','Khadlaj','Una vainilla solar y sofisticada. Captura la esencia de un atardecer en el desierto frente al mar. Es un extracto denso que proyecta una calidez elegante y profundamente seductora. Tamaño: 100 ML (Extrait).','Ámbar Vainilla: Vainilla de Madagascar, notas solares, arena cálida, almizcle.',205000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('0066bdf2-cb07-43bc-90f4-17769d76dd54','Matai Sabah 50 ML EDP','unisex','Matai','\"Mañana\". La frescura del amanecer. Un aroma que proyecta limpieza absoluta y un optimismo renovador para comenzar el día con distinción. Tamaño: 50 ML (EDP).','Nicho Cítrico: Limón de alta gama, notas verdes, almizcle blanco.',650000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('00739042-689a-4106-8dee-db7244297d65','Montale Mukhallat 100 ML EDP','unisex','Montale','Una mezcla exótica y oriental que recuerda a dulces árabes finos. Proyecta una personalidad creativa, audaz y sumamente adictiva. No hay nada que se le parezca. Tamaño: 100 ML (EDP).','Fresa silvestre, almendras, vainilla, bálsamo del Perú, almizcle.',187000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('00778fc1-3660-469f-b4c7-619914bb891c','Estuche Guess Marciano 100 ML HM 3 Pz','hombre','Guess','Elegancia varonil con un toque picante. Un aroma que proyecta seguridad, madurez y un carisma irresistible. Este set de 3 piezas es la firma ideal para el hombre de mundo que valora el buen gusto. Tamaño: 100 ML (HM 3 Pz).','Ámbar Especiado: Jengibre, pimienta, notas de cuero, ámbar, maderas.',200000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('008228be-70ba-43c3-849d-734f6d2a37e2','Al Haramain Amber Oud Gold Edition 200 ML EDP','unisex','Al Haramain','Oro líquido infinito. Formato XL para los amantes del aroma a piña y melón caramelizado. Una joya que llena habitaciones.','Bergamota, notas verdes, melón, piña, notas dulces, vainilla y almizcle.',97000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('00a3fae8-4bf2-46fe-a931-fbbc38365039','Montale Arabians Musk 100 ML EDP','unisex','Montale','Un almizcle rico y envolvente inspirado en la nobleza del caballo árabe. Proyecta una limpieza profunda con un toque de dulzura exótica y adictiva. Tamaño: 100 ML (EDP).','Almizcle Oriental: Miel, almizcle blanco, dátiles, notas dulces.',250000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('00a726d4-6c81-4255-845c-cf10e1b375d5','Body Spray Alhambra Como Moiselle 200 ML DM','mujer','Maison Alhambra','La elegancia millonaria en formato bruma. Inspirada en la opulencia de Chanel Coco Mademoiselle, es perfecta para rociar todo tu cuerpo. Huele a mujer exitosa y sofisticada. Ideal para llevar en el bolso. Tamaño: 200 ML.','Ámbar Floral: Naranja, Rosa turca, Jazmín, Pachulí.',23000.00,400,0,NULL,NULL,NULL,NULL,'2026-04-15 23:24:27','2026-04-15 23:24:27',0,NULL),('011de55d-4c7d-4d65-840a-1eb43be54fad','Afnan Turat